## Steps To Reproduce

1. Open https://codesandbox.io/p/sandbox/kng288?file=%2Fsrc%2FApp.js
2. Press "resolve content of 0"
3. Press "next session"

## The current behavior

nothing happens

## The expected behavior

"session 0" changes to "session 1"

## Full Code

```js
import { useState, use, Suspense, startTransition } from "react";

let nextId = 0;

class Session {
  id = nextId++;
  contentPromise;
  resolveContent;

  constructor() {
    this.contentPromise = new Promise((r) => (this.resolveContent = r));
  }

  static async create() {
    await Promise.resolve();
    return new Session();
  }
}

let initialSessionPromise = Session.create();

export default function App() {
  const [sessionPromise, setSessionPromise] = useState(initialSessionPromise);

  return (
    <Suspense fallback={<p>loading session...</p>}>
      <SessionView
        sessionPromise={sessionPromise}
        onNew={() => startTransition(() => setSessionPromise(Session.create()))}
      />
    </Suspense>
  );
}

function SessionView({ sessionPromise, onNew }) {
  const session = use(sessionPromise);

  return (
    <>
      <p>session {session.id}</p>
      <button onClick={onNew}>new session</button>
      <button onClick={session.resolveContent}>
        resolve content of {session.id}
      </button>
      <Suspense fallback={<p>loading content for {session.id}...</p>}>
        <Content session={session} />
      </Suspense>
    </>
  );
}

function Content({ session }) {
  use(session.contentPromise);
  return <p>content ready for {session.id}</p>;
}
```

