  useEffect(() => {
    stopRecordingRef.current = stopRecording;
  }, [stopRecording]);

  useEffect(() => {
    return () => {
      console.log('Cleaning up in useEffect');
      if (stopRecordingRef.current) {
        stopRecordingRef.current();
